<#
.SYNOPSIS
    dkill2
#>
Write-Host "Starting complete Docker cleanup..." -ForegroundColor Yellow; docker system prune -a --volumes -f 2>$null; docker builder prune -a -f 2>$null; docker buildx prune -a -f 2>$null; try { docker -H npipe:////./pipe/docker_engine_windows system prune -a --volumes -f 2>$null } catch {}; @("Docker Desktop","dockerd","com.docker.proxy","com.docker.backend","com.docker.cli","vpnkit","com.docker.vpnkit","Docker Desktop Installer") | ForEach-Object { Get-Process -Name $_ -ErrorAction SilentlyContinue | Stop-Process -Force -ErrorAction SilentlyContinue }; Start-Sleep 5; Stop-Service -Name "docker" -Force -ErrorAction SilentlyContinue; wsl --shutdown; Start-Sleep 3; Get-Process -Name "wsl*" -ErrorAction SilentlyContinue | Stop-Process -Force -ErrorAction SilentlyContinue; Start-Sleep 3; @("C:\ProgramData\DockerDesktop\vm-data\DockerDesktop.vhdx","C:\Users\$env:USERNAME\AppData\Local\Docker\wsl\disk\DockerDesktop.vhdx","C:\Users\$env:USERNAME\AppData\Local\Docker\wsl\data\DockerDesktop.vhdx","C:\Users\$env:USERNAME\AppData\Local\Docker\wsl\disk\docker_data.vhdx") | ForEach-Object { if (Test-Path $_) { try { Remove-Item $_ -Force -ErrorAction Stop; Write-Host "Deleted: $_" -ForegroundColor Green } catch { takeown /f $_ /a 2>$null; icacls $_ /grant administrators:F 2>$null; Remove-Item $_ -Force -ErrorAction SilentlyContinue } } }; wsl -l -q | Where-Object { $_ -match "docker" } | ForEach-Object { if ($_.Trim()) { wsl --unregister $_.Trim() 2>$null } }; @("$env:TEMP\docker*","$env:TEMP\*docker*","$env:LOCALAPPDATA\Temp\docker*") | ForEach-Object { Get-ChildItem $_ -ErrorAction SilentlyContinue | Remove-Item -Recurse -Force -ErrorAction SilentlyContinue }; Start-Sleep 3; if (Test-Path "C:\Program Files\Docker\Docker\Docker Desktop.exe") { Start-Process "C:\Program Files\Docker\Docker\Docker Desktop.exe"; Start-Sleep 20; Write-Host "Docker cleanup completed!" -ForegroundColor Green }
